package com.smartcampus.service;
import com.itextpdf.text.*;import com.itextpdf.text.pdf.*;import com.smartcampus.entity.EventRegistration;import org.springframework.stereotype.Service;import java.io.ByteArrayOutputStream;
@Service
public class PdfService{
 public byte[] ticket(EventRegistration r){try{ ByteArrayOutputStream out=new ByteArrayOutputStream(); Document doc=new Document(PageSize.A4,40,40,50,40); PdfWriter.getInstance(doc,out); doc.open(); Font title=FontFactory.getFont(FontFactory.HELVETICA_BOLD,22,BaseColor.WHITE); Font h=FontFactory.getFont(FontFactory.HELVETICA_BOLD,14,new BaseColor(61,43,25)); Font n=FontFactory.getFont(FontFactory.HELVETICA,12,BaseColor.DARK_GRAY); PdfPTable header=new PdfPTable(1); header.setWidthPercentage(100); PdfPCell cell=new PdfPCell(new Phrase("SMART CAMPUS PREMIUM EVENT TICKET",title)); cell.setPadding(20); cell.setHorizontalAlignment(Element.ALIGN_CENTER); cell.setBackgroundColor(new BaseColor(93,58,24)); header.addCell(cell); doc.add(header); doc.add(new Paragraph("\n")); PdfPTable t=new PdfPTable(2); t.setWidthPercentage(100); t.setSpacingBefore(10); add(t,"Ticket ID","SCES-"+r.getId(),h,n); add(t,"Full Name",r.getFullName(),h,n); add(t,"Email",r.getPersonalEmail(),h,n); add(t,"Phone",r.getPhone(),h,n); add(t,"Roll No / ID",r.getRollNo(),h,n); add(t,"Department",r.getDepartment(),h,n); add(t,"Academic Year",r.getAcademicYear()==null?"-":r.getAcademicYear(),h,n); add(t,"Attendees",String.valueOf(r.getAttendees()),h,n); add(t,"Event",r.getEvent().getTitle(),h,n); add(t,"Date",String.valueOf(r.getEvent().getEventDate()),h,n); add(t,"Venue",r.getEvent().getVenue(),h,n); add(t,"Status",r.getStatus(),h,n); doc.add(t); doc.add(new Paragraph("\nPlease show this PDF at the registration counter. Thank you for using Smart Campus.",n)); doc.close(); return out.toByteArray(); }catch(Exception e){throw new RuntimeException(e);} }
 private void add(PdfPTable t,String k,String v,Font h,Font n){PdfPCell a=new PdfPCell(new Phrase(k,h)); PdfPCell b=new PdfPCell(new Phrase(v,n)); a.setPadding(10); b.setPadding(10); t.addCell(a); t.addCell(b);}
}
